const $=(s,r=document)=>r.querySelector(s), $$=(s,r=document)=>[...r.querySelectorAll(s)];
const esc=(v='')=>String(v??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
const short=(v='',n=72)=>{const s=String(v||'').replace(/\s+/g,' ').trim();return s.length>n?`${s.slice(0,n)}…`:s};
const api=async p=>{const r=await fetch(p,{cache:'no-store'});if(!r.ok)throw Error(`${r.status}`);return r.json()};
const state={view:'home',today:{},recent:[],body:[],diet:[],training:[],movements:[],movementSelection:'',movementHistory:null,movementUsage:{},usageLoaded:false,page:1};
const main=$('#main'),root=$('#overlay-root'),toast=$('#toast');
const showToast=t=>{toast.textContent=t;toast.classList.add('show');setTimeout(()=>toast.classList.remove('show'),2600)};
const dateOf=r=>String(r.Date||r.date||'').slice(0,10), value=(o,...keys)=>keys.map(k=>o?.[k]).find(v=>v!==undefined&&v!==null&&v!=='')??'—';

function statusPanel(){const t=state.today,b=t.body||{},d=t.diet||{},tr=t.training||{};return `<section class="status-panel"><span class="eyebrow">TODAY / STATUS</span><h2>${esc(t.date||'No record')}</h2><div class="status-row"><span>Weight 体重</span><strong>${esc(value(b,'Weight (kg)'))} kg</strong></div><div class="status-row"><span>Bowel 排便</span><strong>${esc(value(b,'Bowel Movement'))}</strong></div><div class="status-row"><span>Calories 热量</span><strong>${esc(value(d,'Calories (kcal)'))} kcal</strong></div><div class="status-row"><span>Training 分部</span><strong>${esc(value(tr,'split','Split'))}</strong></div><div class="status-row"><span>Cardio 有氧</span><strong>${esc(value(t,'cardio'))}</strong></div></section>`}
function recentPanel(title='RECENT SAVED'){return `<section class="rail-section"><div class="rail-head"><span class="eyebrow">${title}</span><button data-go="body">View all →</button></div>${state.recent.slice(0,4).map(r=>`<article class="record"><h3>${esc(r.date)}</h3><p>${esc(r.weight||'—')} kg · ${esc(r.bowel||'—')} · ${esc(r.calories||'—')} kcal</p><p>${esc(r.split||'Rest')} · ${esc(r.cardio||'No cardio')}</p><div class="record-actions"><button data-record="${esc(r.date)}">Open detail</button><button data-go="training">Training</button><button data-go="diet">Diet</button></div></article>`).join('')}</section>`}
const pageHeader=(title,sub)=>`<header><h1 class="page-title">${title}</h1><p class="page-subtitle">${sub}</p><span class="accent-line"></span></header>`;
const pager=()=>`<div class="pagination records-status"><span>Showing local records</span></div>`;

function homePage(){const t=state.today,b=t.body||{},d=t.diet||{},tr=t.training||{};main.innerHTML=`<section class="home-page"><div class="home-stage"><div class="home-copy"><span class="home-index">01</span><span class="eyebrow">LOCAL FITNESS JOURNAL</span><h1>Daily<br>Capture</h1><p>记录身体、饮食与训练，把自由文字沉淀为可回看的个人档案。</p><div class="home-actions"><button class="btn btn-primary" data-go="quick">Write today's log <span>→</span></button><button class="home-text-link" data-go="movements">Explore movement archive</button></div></div><div class="home-photo" aria-hidden="true"></div><aside class="home-slip"><span class="eyebrow">TODAY / ${esc(t.date||'—')}</span><div class="home-slip-value">${esc(value(b,'Weight (kg)'))}<small>kg</small></div><div class="home-slip-row"><span>${esc(value(tr,'split','Split'))}</span><span>${esc(value(d,'Calories (kcal)'))} kcal</span></div><div class="home-slip-row"><span>${esc(value(t,'cardio'))}</span></div></aside><div class="home-orbit">FREEFORM · REVIEW · STRUCTURED · PRIVATE ·</div></div><section class="home-index-strip"><div class="home-index-head"><span><b>02</b> RECENT ARCHIVE</span><button data-go="body">View full journal →</button></div><div class="home-tickets">${state.recent.slice(0,3).map((r,i)=>`<button class="home-ticket" data-record="${esc(r.date)}"><span class="ticket-no">0${i+1}</span><strong>${esc(r.date)}</strong><small>${esc(r.weight||'—')} kg · ${esc(r.split||'Rest')}</small><em>${esc(r.calories||'—')} kcal</em></button>`).join('')}</div></section></section>`}

function quickPage(){main.innerHTML=`<section class="page entry-page"><header class="entry-header"><div><span class="eyebrow">02 / DAILY ENTRY</span><h1 class="page-title">Write the day.</h1><p class="page-subtitle">Freeform first. Structure follows after review.</p></div><button class="home-text-link" data-go="home">← Back to Home</button></header><div class="entry-spread"><article class="capture"><span class="eyebrow">FREEFORM → STRUCTURED</span><h2>Raw first. Structure second.</h2><textarea id="raw-entry" placeholder="写下今天的任何内容…"></textarea><div class="actions"><button class="btn btn-primary" id="parse">Parse & Review →</button><button class="btn btn-light" data-mock="Undo remains in the stable desktop app.">Undo last save</button></div><p class="phase">Read-only Web preview. Formal writes remain in the stable desktop app.</p></article><aside class="entry-aside">${statusPanel()}${recentPanel()}</aside></div></section>`}

function bodyPage(){main.innerHTML=`<section class="page archive-page"><div class="archive-heading">${pageHeader('Body Records','Daily measurements read as an archive, not a spreadsheet.')}</div><div class="toolbar"><input class="control search" id="body-search" placeholder="Search notes…"><select class="control"><option>All time</option></select><select class="control"><option>Training</option></select><select class="control"><option>Bowel</option></select><select class="control"><option>Cardio</option></select></div><div id="body-rows" class="editorial-records"></div>${pager()}</section>`;renderBodyRows()}
function renderBodyRows(q=''){const rows=state.body.filter(r=>JSON.stringify(r).toLowerCase().includes(q.toLowerCase()));$('#body-rows').innerHTML=rows.map((r,i)=>`<article class="editorial-record ${i===0?'is-featured':''}" data-detail="body" data-index="${state.body.indexOf(r)}"><div class="editorial-date"><span>${String(i+1).padStart(2,'0')}</span><strong>${esc(dateOf(r))}</strong></div><div class="editorial-metrics"><b>${esc(value(r,'Weight (kg)'))}<small>kg</small></b><span>排便 ${esc(value(r,'Bowel Movement'))}</span><span>${esc(value(r,'Training'))}</span><span>${esc(value(r,'Cardio'))}</span></div><p>${esc(short(value(r,'Notes'),110))}</p><button class="record-open">Open record →</button></article>`).join('')}

function dietPage(){main.innerHTML=`<section class="page archive-page diet-archive"><div class="archive-heading">${pageHeader('Diet Records','Meals, macros, and context arranged as daily editorial slips.')}</div><div class="toolbar"><input class="control" value="Recent records" readonly><select class="control"><option>All Meals</option></select><input class="control search" id="diet-search" placeholder="Search notes or food…"></div><div id="diet-rows" class="diet-slips"></div>${pager()}</section>`;renderDietRows()}
function renderDietRows(q=''){const rows=state.diet.filter(r=>JSON.stringify(r).toLowerCase().includes(q.toLowerCase()));$('#diet-rows').innerHTML=rows.map((r,i)=>`<article class="diet-slip ${i%4===1?'slip-offset':''}" data-detail="diet" data-index="${state.diet.indexOf(r)}"><span class="slip-index">${String(i+1).padStart(2,'0')}</span><h3>${esc(dateOf(r))}</h3><div class="macro-line"><strong>${esc(value(r,'Calories (kcal)'))}<small>kcal</small></strong><span>P ${esc(value(r,'Protein (g)'))}</span><span>C ${esc(value(r,'Carbs (g)'))}</span><span>F ${esc(value(r,'Fat (g)'))}</span></div><p>${esc(short(value(r,'Food Summary'),95))}</p><small>${esc(short(value(r,'Notes'),55))}</small><button class="record-open">Read detail →</button></article>`).join('')}

function trainingPage(){main.innerHTML=`<section class="page page-grid"><div class="content">${pageHeader('Training Records','Sessions, movement order, and raw context.')}<div class="toolbar"><input class="control search" id="training-search" placeholder="Search split, movement or notes…"><select class="control"><option>Recent first</option></select></div><div id="session-grid" class="session-grid"></div>${pager()}</div><aside class="rail">${statusPanel()}${recentPanel()}</aside></section>`;renderTraining()}
function renderTraining(q=''){const rows=state.training.filter(r=>JSON.stringify(r).toLowerCase().includes(q.toLowerCase()));$('#session-grid').innerHTML=rows.slice(0,20).map(r=>`<article class="session" data-detail="training" data-index="${state.training.indexOf(r)}"><div class="rail-head"><h3>${esc(dateOf(r))}</h3><span class="tag volt">${esc(value(r,'No.'))}</span></div><p>${esc(value(r,'Split'))}</p><div class="tags">${short(value(r,'Standardized Summary'),100).split(/[，,、]/).slice(0,4).map(t=>`<span class="tag">${esc(t)}</span>`).join('')}</div><p>${esc(short(value(r,'Notes'),90))}</p><button class="link">Open structured detail →</button></article>`).join('')}

const groupLabel=(group='')=>({Chest:'胸部',Back:'背部',Shoulder:'肩部',Shoulders:'肩部',Legs:'腿部',Arms:'手臂',Biceps:'手臂',Triceps:'手臂',Core:'核心',Cardio:'有氧'}[group]||group||'其他');
function movementPage(){main.innerHTML=`<section class="page movement-index-page"><div class="movement-index-hero"><span class="eyebrow">05 / MOVEMENT ARCHIVE</span><h1>Movement<br>Index</h1><p>按训练部位浏览动作。使用频率更高的动作会自然靠前。</p><div class="movement-toolbar"><input id="movement-search" class="control search" placeholder="Search movement, English name or alias…"><span class="result-count">${state.movements.length} movements</span></div></div><div id="movement-list" class="movement-groups"><div class="loading-page"><i></i><p>Reading movement history…</p></div></div></section>`;renderMovementDirectory();loadMovementUsage()}
async function loadMovementUsage(){if(state.usageLoaded){renderMovementDirectory($('#movement-search')?.value||'');return}const pairs=await Promise.all(state.movements.map(async m=>{const name=m.display_name||m.english_name||m.movement_id;try{const payload=await api(`/api/movement-history?name=${encodeURIComponent(name)}&limit=50`);return [name,{count:(payload.history||[]).length,payload}]}catch{return [name,{count:0,payload:null}]}}));state.movementUsage=Object.fromEntries(pairs);state.usageLoaded=true;renderMovementDirectory($('#movement-search')?.value||'')}
function renderMovementDirectory(q=''){const target=$('#movement-list');if(!target)return;const rows=state.movements.filter(m=>JSON.stringify(m).toLowerCase().includes((q||'').toLowerCase())).sort((a,b)=>(state.movementUsage[b.display_name||b.english_name]?.count||0)-(state.movementUsage[a.display_name||a.english_name]?.count||0));const groups=new Map();for(const m of rows){const key=m.muscle_group||'Other';if(!groups.has(key))groups.set(key,[]);groups.get(key).push(m)}const ordered=[...groups.entries()].sort((a,b)=>b[1].reduce((n,m)=>n+(state.movementUsage[m.display_name||m.english_name]?.count||0),0)-a[1].reduce((n,m)=>n+(state.movementUsage[m.display_name||m.english_name]?.count||0),0));const artFor=group=>{const key=String(group||'').toLowerCase();if(/chest|shoulder|push|胸|肩/.test(key))return'movement-art-push.png';if(/back|pull|背/.test(key))return'movement-art-pull.png';if(/leg|glute|lower|腿|臀/.test(key))return'movement-art-legs.png';return'movement-art-arms-core.png'};target.innerHTML=ordered.map(([group,items],groupIndex)=>`<section class="movement-group group-${groupIndex%3}"><header><span class="group-number">${String(groupIndex+1).padStart(2,'0')}</span><div><h2>${esc(groupLabel(group))}</h2><p>${esc(group)} · ${items.length} movements</p></div></header><div class="movement-mosaic">${items.map((m,i)=>{const name=m.display_name||m.english_name||m.movement_id,count=state.movementUsage[name]?.count||0,isLead=i===0&&count;return `<button class="movement-tile ${isLead?'tile-lead':count>=4?'tile-wide':'tile-slip'}" data-select-movement="${esc(name)}">${isLead?`<img class="movement-art" src="assets/${artFor(group)}" alt="" aria-hidden="true">`:''}<span class="tile-count">${count} sessions</span><strong>${esc(name)}</strong><small>${esc(m.english_name&&m.english_name!==name?m.english_name:groupLabel(group))}</small><em>Open trajectory →</em></button>`}).join('')}</div></section>`).join('')||'<p class="empty-note">No matching movements.</p>';const count=$('.result-count');if(count)count.textContent=`${rows.length} movements`}
async function loadMovementFocus(name){state.movementSelection=name;main.innerHTML=`<section class="page movement-detail-page"><button class="movement-back" data-movement-index>← Movement Index</button><div id="movement-focus"><div class="loading-page"><i></i><p>Loading recorded history…</p></div></div></section>`;const focus=$('#movement-focus');try{let payload=state.movementUsage[name]?.payload;if(!payload)payload=await api(`/api/movement-history?name=${encodeURIComponent(name)}&limit=50`);state.movementHistory=payload;const movement=payload.movement||{},history=payload.history||[];focus.innerHTML=`<div class="movement-detail-hero"><span class="eyebrow">RECORDED TRAJECTORY</span><h1>${esc(movement.display_name||name)}</h1><p>${esc(movement.english_name||movement.muscle_group||'Recorded movement')}</p><div class="movement-meta"><span>${esc(groupLabel(movement.muscle_group))}</span><span>${history.length} recorded sessions</span></div></div><div class="trajectory"><div class="trajectory-line"></div>${history.map((r,i)=>`<article class="trajectory-entry ${i===0?'is-latest':''}"><div class="trajectory-marker">${String(i+1).padStart(2,'0')}</div><div class="history-date"><strong>${esc(r.date||'—')}</strong><small>Day ${esc(r.training_day??'—')} · Ex ${esc(r.order??'—')}</small></div><div class="history-content"><h3>${esc((r.sets_lines||[]).join(' · ')||'Recorded without structured sets')}</h3>${r.notes?`<p>${esc(r.notes)}</p>`:''}</div></article>`).join('')||'<div class="empty-copy"><h3>No history yet</h3><p>This movement exists in the dictionary but has no recorded sessions.</p></div>'}</div>`}catch{focus.innerHTML='<div class="empty-copy"><h3>History unavailable</h3><p>The local read-only service could not load this movement.</p></div>'}}

const issues=[['High','2026-07-01','身体数据','缺少排便记录','补充当天排便信息'],['High','2026-06-29','训练记录','发现未识别动作','审核动作并映射或加入词典'],['Medium','2026-06-30','训练记录','检测到同日重复记录','检查并决定保留或合并'],['Medium','2026-06-25','身体数据','字段内容可能混入其他文字','打开记录并清理字段'],['Medium','2026-06-24','训练记录','动作组数未能结构化识别','核对并补充组数'],['Low','2026-06-20','饮食记录','缺少热量数据','补充当天热量']];
function checksPage(){main.innerHTML=`<section class="page page-grid"><div class="content">${pageHeader('Data Check','Unresolved issues, data hygiene, and structural consistency.')}<div class="toolbar"><button class="btn btn-primary">All Issues &nbsp; 6</button><button class="btn">High 2</button><button class="btn">Medium 3</button><button class="btn">Low 1</button></div><div class="table-wrap"><table><thead><tr><th>SEVERITY</th><th>DATE</th><th>AREA</th><th>ISSUE</th><th>SUGGESTED ACTION</th><th>OPEN</th></tr></thead><tbody>${issues.map((x,i)=>`<tr data-issue="${i}"><td><span class="severity ${x[0].toLowerCase()}">${x[0]}</span></td><td>${x[1]}</td><td>${x[2]}</td><td>${x[3]}</td><td>${x[4]}</td><td><button class="link">Open</button></td></tr>`).join('')}</tbody></table></div>${pager()}</div><aside class="rail"><section class="rail-section" style="margin-top:0"><span class="eyebrow">NEW MOVEMENT APPROVAL</span><h2 style="font:400 24px var(--serif)">Movement detected</h2><p>Z-Press (Dumbbell)</p><button class="btn btn-primary" data-approval style="width:100%">Review decision</button></section><section class="rail-section"><span class="eyebrow">COMPONENT STATES</span><div class="state-stack" style="margin-top:16px"><div class="state">Empty · No matching issues</div><div class="state">Loading · Scanning data</div><div class="state success">Success · All good</div><div class="state warning">Warning · Needs attention</div><div class="state error">Error · Scan interrupted</div></div></section><p style="color:#666;font-size:11px">UI preview only. The stable desktop checker remains authoritative.</p></aside></section>`}

function reviewPage(raw){main.innerHTML=`<section class="page review"><div class="review-top">${pageHeader('Parse & Review','Review extracted data before saving to your local journal.')}<button class="btn" data-back>Back to edit</button></div><div class="summary-strip">${[['Date','2026-07-01'],['Weight','67.8 kg'],['Bowel','少量'],['Calories','1570 kcal'],['Training','胸部, 肩部'],['Movements','6 · New 1']].map(x=>`<div class="metric"><label>${x[0]}</label><strong>${x[1]}</strong></div>`).join('')}</div>${['BODY 身体','DIET 饮食','TRAINING 训练','MOVEMENTS 动作识别','WARNINGS 警告'].map((t,i)=>`<section class="review-section"><h3>${t}</h3><p>${i===4?'Duplicate date · New movement · Unrecognized sets':i===3?'1. 卧推 · 4 sets &nbsp; 2. 引体向上 · 3 sets &nbsp; 3. 绳索面拉 · 3 sets':esc(short(raw||'Preview data from the current draft.',180))}</p></section>`).join('')}<div class="bottom-bar"><button class="btn" data-back>Cancel</button><button class="btn" data-back>← Back to edit</button><button class="btn btn-primary" data-duplicate>Confirm & Save</button></div></section>`}

function modal(title,content,{light=false,actions=''}={}){root.innerHTML=`<div class="overlay"><section class="modal ${light?'light':''}"><button class="close" data-close>×</button><h2>${esc(title)}</h2>${content}${actions?`<div class="modal-actions">${actions}</div>`:''}</section></div>`}
function detail(kind,index){const map={body:state.body,diet:state.diet,training:state.training},r=map[kind][index];const rows=Object.entries(r||{}).filter(([,v])=>v!==''&&v!=null).map(([k,v])=>`<div class="detail-row"><label>${esc(k)}</label><div>${esc(typeof v==='object'?JSON.stringify(v):v)}</div></div>`).join('');modal(`${kind[0].toUpperCase()+kind.slice(1)} Detail`,rows,{light:kind==='diet',actions:`<button class="btn" data-mock="Editing is available in the stable desktop app.">Edit</button><button class="btn btn-primary" data-close>Close</button>`})}
async function recordDetail(date){modal(date,'<div class="loading-page" style="height:240px"><i></i></div>');try{const r=await api(`/api/record?date=${encodeURIComponent(date)}`);$('.modal').innerHTML=`<button class="close" data-close>×</button><h2>${esc(date)}</h2><div class="detail-list">${Object.entries(r).map(([k,v])=>`<div class="detail-row"><label>${esc(k)}</label><div>${esc(short(typeof v==='object'?JSON.stringify(v,null,2):v,500))}</div></div>`).join('')}</div>`}catch{showToast('Unable to load record detail.')}}
async function movementDetail(name){modal(name,'<div class="loading-page" style="height:240px"><i></i></div>');try{const h=await api(`/api/movement-history?name=${encodeURIComponent(name)}&limit=8`);$('.modal').innerHTML=`<button class="close" data-close>×</button><span class="eyebrow">MOVEMENT HISTORY</span><h2>${esc(name)}</h2><div class="detail-list">${(h.history||h.records||h||[]).map(r=>`<div class="detail-row"><label>${esc(dateOf(r))}</label><div>${esc(short(value(r,'sets_summary','raw_detail','detail'),220))}</div></div>`).join('')||'<p>No structured history found.</p>'}<div class="modal-actions"><button class="btn" data-drawer="movement">Open editor preview</button><button class="btn btn-primary" data-close>Close</button></div>`}catch{showToast('Unable to load movement history.')}}
function drawer(type){const light=type==='movement';root.innerHTML=`<div class="overlay" data-close></div><aside class="drawer ${light?'light':''}"><button class="close" data-close>×</button><span class="eyebrow" style="${light?'color:#676962':''}">${type==='movement'?'MOVEMENT EDITOR':'RECORD EDITOR · UI PREVIEW'}</span><h2 style="font:400 30px var(--serif)">${type==='movement'?'Movement record':'Edit Body Record'}</h2>${['Date','Name / Training','Weight or Sets','Cardio','Notes'].map((f,i)=>`<label class="field"><span>${f}</span>${i===4?'<textarea rows="5">Preview only</textarea>':`<input value="${i===0?'2026-07-01':''}">`}</label>`).join('')}<button class="btn btn-primary" style="width:100%" data-mock="Write actions are intentionally disabled in Web preview.">Save changes</button></aside>`}
function duplicate(){modal('Duplicate Date Detected',`<p>2026-07-01 的记录已存在。请选择如何处理此记录：</p><div class="detail-list"><button class="btn btn-primary" data-mock="Overwrite is disabled in read-only preview.">Overwrite daily records →</button><button class="btn btn-light" data-mock="Adding a session is disabled in read-only preview.">Add as second training session →</button><button class="btn btn-light" data-close>Cancel</button></div>`,{light:true})}
function approval(){modal('New movement approval',`<p>This movement is not in your dictionary.</p><div class="detail-row"><label>Detected</label><strong>Z-Press (Dumbbell)</strong></div><div class="detail-list"><label class="record"><input type="radio" name="a" checked> Add to dictionary</label><label class="record"><input type="radio" name="a"> Map to existing movement</label><label class="record"><input type="radio" name="a"> Keep raw only</label></div>`,{actions:`<button class="btn" data-close>Cancel</button><button class="btn btn-primary" data-mock="Approval is a UI preview only.">Save decision</button>`})}

/* Visual-only archive overrides. These keep the same data/API contracts while repairing dense Chinese layout. */
bodyPage=function(){main.innerHTML=`<section class="page archive-page body-archive"><div class="archive-heading">${pageHeader('Body Records','Daily measurements as personal body slips, with notes kept readable.')}</div><div class="toolbar body-toolbar"><input class="control search" id="body-search" placeholder="Search notes..."><select class="control"><option>All time</option></select><select class="control"><option>Training</option></select><select class="control"><option>Bowel</option></select><select class="control"><option>Cardio</option></select></div><div id="body-rows" class="body-ledger"></div>${pager()}</section>`;renderBodyRows()}
renderBodyRows=function(q=''){const rows=state.body.filter(r=>JSON.stringify(r).toLowerCase().includes(q.toLowerCase()));$('#body-rows').innerHTML=rows.map((r,i)=>`<article class="body-slip ${i===0?'is-featured':''}" data-detail="body" data-index="${state.body.indexOf(r)}"><div class="body-slip-date"><span>${String(i+1).padStart(2,'0')}</span><strong>${esc(dateOf(r))}</strong></div><div class="body-slip-weight"><b>${esc(value(r,'Weight (kg)'))}</b><small>kg</small></div><div class="body-slip-meta"><span>排便 <strong>${esc(value(r,'Bowel Movement'))}</strong></span><span>训练 <strong>${esc(short(value(r,'Training'),24))}</strong></span><span>有氧 <strong>${esc(short(value(r,'Cardio'),24))}</strong></span></div><p>${esc(short(value(r,'Notes'),160))}</p><button class="record-open">Open record →</button></article>`).join('')}
dietPage=function(){main.innerHTML=`<section class="page archive-page diet-archive"><div class="archive-heading">${pageHeader('Diet Records','Meals, macros, and context arranged as daily editorial slips.')}</div><div class="toolbar diet-toolbar"><input class="control" value="Recent records" readonly><select class="control"><option>All Meals</option></select><input class="control search" id="diet-search" placeholder="Search notes or food..."></div><div id="diet-rows" class="diet-slips"></div>${pager()}</section>`;renderDietRows()}
