checksPage=function(){main.innerHTML=`<section class="page page-grid checks-page"><div class="content">${pageHeader('Data Check','检查未解决的数据问题；只有明确的 Open 入口会打开详情。')}<div class="toolbar check-filters"><button class="btn btn-primary is-selected" data-check-filter="all">全部问题 &nbsp; ${issues.length}</button><button class="btn" data-check-filter="high">高 2</button><button class="btn" data-check-filter="medium">中 3</button><button class="btn" data-check-filter="low">低 1</button></div><div class="table-wrap check-table-wrap"><table class="check-table"><thead><tr><th>级别</th><th>日期</th><th>区域</th><th>问题</th><th>建议处理</th><th>详情</th></tr></thead><tbody>${issues.map((x,i)=>`<tr data-severity="${x[0].toLowerCase()}"><td><span class="severity ${x[0].toLowerCase()}">${x[0]}</span></td><td>${x[1]}</td><td>${x[2]}</td><td>${x[3]}</td><td>${x[4]}</td><td><button class="link issue-open" data-open-issue="${i}">Open</button></td></tr>`).join('')}</tbody></table></div><div class="records-status" aria-live="polite">显示 ${issues.length} 个本地问题</div></div><aside class="rail"><section class="rail-section" style="margin-top:0"><span class="eyebrow">处理原则</span><h2 style="font:400 24px var(--serif)">由你确认，再进行修正</h2><p>网页查看端只展示问题详情，不会自动修改本地数据。</p></section><section class="rail-section"><span class="eyebrow">状态说明</span><div class="state-stack" style="margin-top:16px"><div class="state error">High · 优先核对</div><div class="state warning">Medium · 影响准确性</div><div class="state success">Low · 提示性问题</div></div></section></aside></section>`}

const compactSearch=value=>String(value??'').normalize('NFKC').toLowerCase().replace(/[\s\-_./\\，。；、:：()（）]+/g,'');
function dateParts(value){const match=String(value??'').match(/(?:\d{4}[-/.])?(\d{1,2})[-/.](\d{1,2})/);return match?[Number(match[1]),Number(match[2])]:null}
function fuzzyMatch(record,query){const raw=String(query??'').trim();if(!raw)return true;const compact=compactSearch(JSON.stringify(record)),terms=raw.split(/\s+/).map(compactSearch).filter(Boolean);if(terms.every(term=>compact.includes(term)))return true;const wanted=dateParts(raw),actual=dateParts(dateOf(record));return Boolean(wanted&&actual&&wanted[0]===actual[0]&&wanted[1]===actual[1])}
function latestRecordDate(rows){return rows.reduce((latest,row)=>{const date=new Date(`${dateOf(row)}T00:00:00`);return Number.isNaN(date.valueOf())||date<latest?latest:date},new Date(0))}
function withinDays(row,days,rows){if(!days)return true;const latest=latestRecordDate(rows),date=new Date(`${dateOf(row)}T00:00:00`);return !Number.isNaN(date.valueOf())&&(latest-date)/86400000<days}
const selectedValue=id=>document.getElementById(id)?.value||'all';

