renderBodyRows=function(q=$('#body-search')?.value||''){const time=Number(selectedValue('body-time'))||0,trainingFilter=selectedValue('body-training'),bowelFilter=selectedValue('body-bowel'),cardioFilter=selectedValue('body-cardio');const rows=state.body.filter(r=>{const training=String(value(r,'Training')).toLowerCase(),bowel=String(value(r,'Bowel Movement')).toLowerCase(),cardio=String(value(r,'Cardio')).toLowerCase();const rest=/休息|rest|none|无训练/.test(training),bowelNo=/^\s*$|否|无|none|not/.test(bowel),cardioNo=/^\s*$|none|无有氧|无|^-$/.test(cardio);return fuzzyMatch(r,q)&&withinDays(r,time,state.body)&&(trainingFilter==='all'||(trainingFilter==='rest'&&rest)||(trainingFilter==='trained'&&!rest))&&(bowelFilter==='all'||(bowelFilter==='no'&&bowelNo)||(bowelFilter==='yes'&&!bowelNo))&&(cardioFilter==='all'||(cardioFilter==='no'&&cardioNo)||(cardioFilter==='yes'&&!cardioNo))});$('#body-rows').innerHTML=rows.map((r,i)=>{const cardio=String(value(r,'Cardio')).toLowerCase(),training=String(value(r,'Training'));let tone='tone-purple';if(i===0)tone='tone-feature';else if(/back|背/.test(training.toLowerCase()))tone='tone-cardio';else if(/chest|胸|shoulder|肩/.test(training.toLowerCase()))tone='tone-purple';else if(/leg|腿/.test(training.toLowerCase()))tone='tone-training';else if(/none|no cardio|-/.test(cardio))tone='tone-rest';return `<article class="body-slip ${tone}"><div class="body-slip-date"><span>${String(i+1).padStart(2,'0')}</span><strong>${esc(dateOf(r))}</strong></div><div class="body-slip-weight"><b>${esc(value(r,'Weight (kg)'))}</b><small>kg</small></div><div class="body-slip-meta"><span>Bowel <strong>${esc(value(r,'Bowel Movement'))}</strong></span><span>Training <strong>${esc(short(training,24))}</strong></span><span>Cardio <strong>${esc(short(value(r,'Cardio'),24))}</strong></span></div><div class="body-slip-copy"><p>${esc(short(value(r,'Notes'),160))}</p><button class="record-open" data-detail="body" data-index="${state.body.indexOf(r)}">Open record</button></div></article>`}).join('')||'<p class="empty-note">No body records match these filters.</p>'}

dietPage=function(){main.innerHTML=`<section class="page archive-page diet-archive"><div class="archive-heading">${pageHeader('Diet Records','Energy and macros first. Full meals remain one deliberate click away.')}</div><div class="toolbar diet-toolbar"><select class="control" id="diet-meal"><option value="all">All meals</option><option value="早餐">Breakfast</option><option value="练前">Pre-workout</option><option value="练后">Post-workout</option><option value="晚餐">Dinner</option><option value="加餐">Snacks</option></select><input class="control search" id="diet-search" placeholder="Search food or date..."></div><div id="diet-rows" class="diet-slips"></div>${pager()}</section>`;renderDietRows()}
